import { spawn } from 'node:child_process';
import { access, mkdtemp, readFile, realpath, rm, writeFile } from 'node:fs/promises';
import { constants as fsConstants } from 'node:fs';
import { tmpdir } from 'node:os';
import { join, resolve } from 'node:path';
import { machInvocation } from './mach.js';
import { projectPaths } from './project.js';
export async function verifyProject(cwd = process.cwd(), timeoutMs = 30_000) {
    const paths = await projectPaths(cwd);
    const source = await realpath(paths.firefoxSource);
    const mach = resolve(source, process.platform === 'win32' ? 'mach.ps1' : 'mach');
    try {
        await access(mach, process.platform === 'win32' ? fsConstants.F_OK : fsConstants.X_OK);
    }
    catch {
        throw new Error(`Mozilla mach executable not found: ${mach}`);
    }
    const profile = await mkdtemp(join(tmpdir(), 'geckokit-verify-'));
    await writeFile(resolve(profile, 'user.js'), 'user_pref("geckokit.verification.enabled", true);\n');
    const invocation = machInvocation(source, ['run', '--profile', profile, '--no-remote']);
    try {
        const result = await new Promise((resolveRun, reject) => {
            const child = spawn(invocation.command, invocation.args, {
                cwd: source,
                env: { ...process.env, MOZCONFIG: resolve(paths.projectDirectory, 'mozconfig') },
                stdio: ['ignore', 'pipe', 'pipe'],
            });
            let output = '';
            const capture = (chunk) => {
                output = `${output}${chunk.toString()}`.slice(-16_384);
            };
            child.stdout.on('data', capture);
            child.stderr.on('data', capture);
            const timer = setTimeout(() => {
                child.kill('SIGKILL');
                reject(new Error(`Firefox startup verification timed out after ${timeoutMs}ms.`));
            }, timeoutMs);
            child.once('error', (error) => {
                clearTimeout(timer);
                reject(error);
            });
            child.once('close', (code) => {
                clearTimeout(timer);
                resolveRun({ code, output });
            });
        });
        const prefs = await readFile(resolve(profile, 'prefs.js'), 'utf8').catch(() => '');
        if (result.code !== 0 ||
            !/user_pref\("geckokit\.verification\.passed", true\);/.test(prefs)) {
            throw new Error(`Firefox startup verification failed.${result.output.trim() ? `\n${result.output.trim()}` : ''}`);
        }
    }
    finally {
        await rm(profile, { recursive: true, force: true });
    }
}
